export interface IRegion {
  chr?: string
  start: number
  end: number
  offset?: number
  strand?: '+' | '-'
  gene_id?: string
  trans_id?: string
  trans_name?: string
  trans_type?: string
  have_offset?: boolean
}

export interface IRenderParams {
  cellWidth: number
  featureLeft: number
  featureTop?: number // feature 的顶部位置
  screenWidth: number
  minRectWidth?: number // 最小矩形宽度，用于保证信号可见性
  trackHeight?: number // feature 的高度，用于计算 bar 的高度
  paddingBottom?: number // feature 的底部 padding
  plot?: string // 渲染类型，用于判断是否需要特殊计算
  color?: string | string[] | { [key: string]: string } // 🎨 颜色配置，可以是单色、数组或渐变色名称
}

export interface IAnnotation {
  keys?: string[]
  order?: string[]
  expand?: string | boolean
  colors?: string[] | { [key: string]: string } | string
  sep?: string
}

export interface IPixelCoords {
  x: number[] // 渲染 X 坐标（像素位置）
  y: number[] // 渲染 Y 坐标（像素位置，bar 图的底部位置）
  width: number[] // 渲染宽度（已应用 minRectWidth）
  height: number[] // 渲染高度（bar 图专用，Worker 预计算）
  colors: string[] // 渲染颜色（Worker 预计算）
  flank: number[] // -1: 左侧屏, 0: 当前屏, 1: 右侧屏
}

export interface IWorkerMessage {
  data: any
  type: string
  plot: string
  region: IRegion
  regionData?: any
  annotation?: IAnnotation
  renderParams?: IRenderParams
  // CDS 模式相关
  axisType?: 'DNA' | 'RNA' | 'CDS' // 当前坐标轴类型
  cdsData?: { position: number[] } // CDS 位置数组
}

export interface IWorkerResponse {
  success: boolean
  data?: any
  error?: {
    message: string
  }
}

export interface IFormatResult {
  name: string
  size: number
  plot: string
  start: number[] // 基因组坐标
  end: number[] // 基因组坐标
  score?: number[]
  range?: [number, number]
  props?: any
  info?: any[]
  children?: any[]
  pixelCoords?: IPixelCoords // 像素坐标和 flank 标记
  [key: string]: any
}
